#[test]
fn bindgen_test_layout_fz_function() {
    const UNINIT: ::std::mem::MaybeUninit<fz_function> = ::std::mem::MaybeUninit::uninit();
    let ptr = UNINIT.as_ptr();
    assert_eq!(
        ::std::mem::size_of::<fz_function>(),
        48usize,
        concat!("Size of: ", stringify!(fz_function))
    );
    assert_eq!(
        ::std::mem::align_of::<fz_function>(),
        8usize,
        concat!("Alignment of ", stringify!(fz_function))
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).storable) as usize - ptr as usize },
        0usize,
        concat!(
            "Offset of field: ",
            stringify!(fz_function),
            "::",
            stringify!(storable)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).size) as usize - ptr as usize },
        24usize,
        concat!(
            "Offset of field: ",
            stringify!(fz_function),
            "::",
            stringify!(size)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).m) as usize - ptr as usize },
        32usize,
        concat!(
            "Offset of field: ",
            stringify!(fz_function),
            "::",
            stringify!(m)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).n) as usize - ptr as usize },
        36usize,
        concat!(
            "Offset of field: ",
            stringify!(fz_function),
            "::",
            stringify!(n)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).eval) as usize - ptr as usize },
        40usize,
        concat!(
            "Offset of field: ",
            stringify!(fz_function),
            "::",
            stringify!(eval)
        )
    );
}
