#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct pdf_filespec_params {
    pub filename: *const ::std::os::raw::c_char,
    pub mimetype: *const ::std::os::raw::c_char,
    pub size: ::std::os::raw::c_int,
    pub created: i64,
    pub modified: i64,
}
#[test]
fn bindgen_test_layout_pdf_filespec_params() {
    const UNINIT: ::std::mem::MaybeUninit<pdf_filespec_params> = ::std::mem::MaybeUninit::uninit();
    let ptr = UNINIT.as_ptr();
    assert_eq!(
        ::std::mem::size_of::<pdf_filespec_params>(),
        40usize,
        concat!("Size of: ", stringify!(pdf_filespec_params))
    );
    assert_eq!(
        ::std::mem::align_of::<pdf_filespec_params>(),
        8usize,
        concat!("Alignment of ", stringify!(pdf_filespec_params))
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).filename) as usize - ptr as usize },
        0usize,
        concat!(
            "Offset of field: ",
            stringify!(pdf_filespec_params),
            "::",
            stringify!(filename)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).mimetype) as usize - ptr as usize },
        8usize,
        concat!(
            "Offset of field: ",
            stringify!(pdf_filespec_params),
            "::",
            stringify!(mimetype)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).size) as usize - ptr as usize },
        16usize,
        concat!(
            "Offset of field: ",
            stringify!(pdf_filespec_params),
            "::",
            stringify!(size)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).created) as usize - ptr as usize },
        24usize,
        concat!(
            "Offset of field: ",
            stringify!(pdf_filespec_params),
            "::",
            stringify!(created)
        )
    );
    assert_eq!(
        unsafe { ::std::ptr::addr_of!((*ptr).modified) as usize - ptr as usize },
        32usize,
        concat!(
            "Offset of field: ",
            stringify!(pdf_filespec_params),
            "::",
            stringify!(modified)
        )
    );
}
